#!/usr/bin/env node
/**
 * Writes api-config.js from PUBLIC_API_URL (Vercel / CI).
 * Example: PUBLIC_API_URL=https://your-app.up.railway.app
 */
const fs = require('fs');
const path = require('path');

const root = path.join(__dirname, '..');
const url = (process.env.PUBLIC_API_URL || '').trim().replace(/\/+$/, '');
const content =
    '// Generated by scripts/write-api-config.js\n' +
    'window.__SKY_SMART_API_ORIGIN__=' +
    JSON.stringify(url) +
    ';\n';

fs.writeFileSync(path.join(root, 'api-config.js'), content);
console.log('[write-api-config] PUBLIC_API_URL =', url || '(empty — same-origin)');
